import{_ as a,a as t,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as r,o,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Añadir un canal Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/yandex.md","filePath":"es/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"es/upload/yandex.md"};function c(p,e,h,u,b,m){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="anadir-un-canal-yandex" tabindex="-1">Añadir un canal Yandex <a class="header-anchor" href="#anadir-un-canal-yandex" aria-label="Permalink to &quot;Añadir un canal Yandex&quot;">​</a></h1><p>El canal Yandex usa Yandex Disk como destino de almacenamiento.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Yandex</td><td>Autorizar Yandex Disk</td></tr><tr><td>Yandex OAuth App</td><td>Obtener Client ID y Client Secret</td></tr><tr><td>Dominio ImgBed</td><td>Configurar callback OAuth</td></tr><tr><td>Yandex Disk</td><td>Guardar los archivos</td></tr></tbody></table><h2 id="crear-yandex-oauth-app" tabindex="-1">Crear Yandex OAuth App <a class="header-anchor" href="#crear-yandex-oauth-app" aria-label="Permalink to &quot;Crear Yandex OAuth App&quot;">​</a></h2><p>Abre:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><p>Si pide inicio de sesión, entra con la cuenta de Yandex que vas a usar como almacenamiento.</p><p>Crea una aplicación y ponle un nombre reconocible:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-yandex</span></span></code></pre></div><p>En callback URL, introduce:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/api/oauth/yandex/callback</span></span></code></pre></div><h2 id="permisos" tabindex="-1">Permisos <a class="header-anchor" href="#permisos" aria-label="Permalink to &quot;Permisos&quot;">​</a></h2><p>ImgBed usa estos permisos de <code>Yandex.Disk REST API</code>:</p><table tabindex="0"><thead><tr><th>Permiso</th><th>Uso</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Guardar archivos en la carpeta de la app</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Leer archivos y enlaces de descarga</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Subir, crear carpetas y borrar</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Leer capacidad y uso</td></tr></tbody></table><p>Los permisos de nombre o correo dentro de <code>Yandex ID API</code> son opcionales. Las funciones principales dependen de los permisos de Disk.</p><p><img src="'+a+'" alt="Permisos Yandex Disk" loading="lazy"></p><h2 id="copiar-client-id-y-secret" tabindex="-1">Copiar Client ID y Secret <a class="header-anchor" href="#copiar-client-id-y-secret" aria-label="Permalink to &quot;Copiar Client ID y Secret&quot;">​</a></h2><p>Tras crear la aplicación, copia:</p><table tabindex="0"><thead><tr><th>Campo Yandex</th><th>Campo ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Client ID y Secret" loading="lazy"></p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, elige <code>Yandex</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Por ejemplo <code>Yandex Main</code></td></tr><tr><td>Client ID</td><td>Client ID de la app</td></tr><tr><td>Client Secret</td><td>Client Secret de la app</td></tr><tr><td>Refresh Token</td><td>Déjalo vacío al principio</td></tr><tr><td>Directorio raíz</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><p><img src="'+d+'" alt="Configuración Yandex" loading="lazy"></p><h2 id="obtener-refresh-token" tabindex="-1">Obtener Refresh Token <a class="header-anchor" href="#obtener-refresh-token" aria-label="Permalink to &quot;Obtener Refresh Token&quot;">​</a></h2><ol><li>En ImgBed, pulsa <code>Obtener Token</code>.</li><li>Inicia sesión con la cuenta de Yandex de destino.</li><li>Acepta los permisos.</li><li>Copia el <code>Refresh Token</code> mostrado en la página de callback.</li><li>Pégalo en ImgBed.</li></ol><p><img src="'+n+`" alt="Refresh Token" loading="lazy"></p><h2 id="flujo-rapido" tabindex="-1">Flujo rápido <a class="header-anchor" href="#flujo-rapido" aria-label="Permalink to &quot;Flujo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Abrir Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Crear App</span></span>
<span class="line"><span>-&gt; Configurar https://tu-dominio/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Confirmar permisos Disk</span></span>
<span class="line"><span>-&gt; Copiar Client ID / Client Secret</span></span>
<span class="line"><span>-&gt; Rellenar en ImgBed</span></span>
<span class="line"><span>-&gt; Obtener Token</span></span>
<span class="line"><span>-&gt; Pegar Refresh Token y guardar</span></span></code></pre></div><h2 id="referencias" tabindex="-1">Referencias <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referencias&quot;">​</a></h2><ol><li>Registrar app Yandex: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Código de autorización por URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>API de token OAuth: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,32)])])}const y=r(l,[["render",c]]);export{k as __pageData,y as default};
